# BEST PRACTICE: Adaptive Pattern Selection
class AdaptiveMultiHopRetriever:
    def __init__(self, simple_threshold=0.7, hop_budget=3):
        self.simple_threshold = simple_threshold
        self.hop_budget = hop_budget

    def retrieve(self, cricket_query):
        complexity_score = self.estimate_query_complexity(cricket_query)

        if complexity_score < self.simple_threshold:
            # Single-hop sufficient: "Who won the 2023 World Cup?"
            return self.single_hop_retrieve(cricket_query)

        elif complexity_score < 0.85:
            # Sequential chain: decompose and iterate
            return self.sequential_chain_retrieve(
                cricket_query, 
                max_hops=self.hop_budget
            )

        else:
            # Parallel exploration for high-complexity: "Compare batting strategies across formats"
            return self.parallel_fan_out_retrieve(
                cricket_query, 
                num_paths=3,
                max_hops=self.hop_budget
            )

    def estimate_query_complexity(self, query):
        features = [
            len(query.split()),  # Length
            query.count("vs"),   # Comparisons
            query.count("why"),  # Reasoning chains
        ]
        return min(1.0, sum(features) / len(features))

# ANTI-PATTERN: Always using Parallel (wastes tokens and latency)
class NaiveMultiHopRetriever:
    def retrieve(self, cricket_query):
        # Indiscriminately parallelizes ALL queries
        paths = []
        for _ in range(5):  # Fixed 5 paths, regardless of complexity
            paths.append(self.retrieve_path(cricket_query))
        return self.rank_paths(paths)

